# role assignment (the Terraform SP is Contributor-only and can't grant roles).
resource "azurerm_container_registry" "harness" {
  name                = "${var.acr_prefix}${random_string.suffix.result}"
  resource_group_name = data.azurerm_resource_group.dataq.name
  location            = var.azure_location
  sku                 = "Basic"
  admin_enabled       = true
  tags                = local.common_tags
}
========== redis.tf ==========
# Redis broker for Airflow CeleryExecutor (§3 / execution scaling).
# Self-hosted Redis container (not Azure Cache for Redis) — cheapest + fastest for a
# disposable harness; the broker is transient (no persistence needed). Internal-only
# TCP ingress so only the Airflow scheduler + workers in this environment reach it.
resource "azurerm_container_app" "redis" {
  name                         = "dataq-harness-redis"
  container_app_environment_id = azurerm_container_app_environment.harness.id
  resource_group_name          = data.azurerm_resource_group.dataq.name
  revision_mode                = "Single"

  ingress {
    external_enabled = false # only reachable within the Container Apps environment
    transport        = "tcp"
    target_port      = 6379
    exposed_port     = 6379
    traffic_weight {
      latest_revision = true
      percentage      = 100
    }
  }

  template {
    min_replicas = 1
    max_replicas = 1
    container {
      name   = "redis"
      image  = "redis:7-alpine" # public image — no registry auth needed
      cpu    = 0.5
      memory = "1Gi"
      # default redis-server entrypoint is fine for a transient broker (RDB snapshots
      # are harmless here; azurerm can't serialize an empty-string arg for --save "").
    }
  }

  tags = local.common_tags
}
